1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const insuranceValueForType = (type: string): number => INSURANCE_VALUE_BY_TYPE[type] ?? 0;
32	
33	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM_BY_TYPE));
34	
35	const validateItemTypes = (items: Item[]): void => {
36	  for (const item of items) {
37	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
38	      throw new Error(`Unknown item type: ${item.type}`);
39	    }
40	  }
41	};
42	
43	const DEDUCTIBLE = 100;
44	const CAP_MULTIPLIER = 2;
45	
46	const policyInsuranceSum = (items: Item[]): number =>
47	  sum(items.map((item) => insuranceValueForType(item.type)));
48	
49	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
50	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
51	
52	const reimbursableAmount = (damage: Damage, item: Item | undefined): number => {
53	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
54	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
55	  }
56	  return damage.amount;
57	};
58	
59	const damagePayout = (damage: Damage, item: Item | undefined): number =>
60	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
61	
62	const countByType = (xs: { type?: string; itemType?: string }[], key: "type" | "itemType"): Map<string, number> => {
63	  const counts = new Map<string, number>();
64	  for (const x of xs) {
65	    const k = x[key] as string;
66	    counts.set(k, (counts.get(k) ?? 0) + 1);
67	  }
68	  return counts;
69	};
70	
71	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
72	  const itemCounts = countByType(items, "type");
73	  const damageCounts = countByType(damages, "itemType");
74	  for (const [type, count] of damageCounts) {
75	    if (count > (itemCounts.get(type) ?? 0)) {
76	      throw new Error(`Claim has ${count} damages of type ${type} but policy covers only ${itemCounts.get(type) ?? 0}`);
77	    }
78	  }
79	};
80	
81	const validateDamageAmounts = (damages: Damage[]): void => {
82	  for (const damage of damages) {
83	    if (damage.amount < 0) {
84	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
85	    }
86	  }
87	};
88	
89	const processClaim = (
90	  items: Item[],
91	  incident: Incident,
92	  remainingCap: number,
93	): { payout: number; remainingCap: number } => {
94	  validateDamageAmounts(incident.damages);
95	  validateDamageCounts(items, incident.damages);
96	  const rawPayout = sum(
97	    incident.damages.map((damage) =>
98	      damagePayout(damage, items.find((item) => item.type === damage.itemType)),
99	    ),
100	  );
101	  const payout = Math.floor(Math.min(rawPayout, remainingCap));
102	  return { payout, remainingCap: remainingCap - payout };
103	};
104	
105	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
106	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
107	
108	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
109	const BLOCK_SIZE = 3;
110	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
111	
112	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
113	
114	const componentGroupPremium = (type: string, count: number): number =>
115	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
116	
117	const groupByType = (items: Item[]): Map<string, number> => {
118	  const counts = new Map<string, number>();
119	  for (const item of items) {
120	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
121	  }
122	  return counts;
123	};
124	
125	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
126	
127	const policyBasePremium = (items: Item[]): number => {
128	  const mainItems = items.filter((item) => !isComponent(item));
129	  const componentItems = items.filter(isComponent);
130	  const componentCounts = groupByType(componentItems);
131	
132	  const mainTotal = sum(mainItems.map(itemBasePremium));
133	  const componentTotal = sum(
134	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
135	  );
136	
137	  return mainTotal + componentTotal;
138	};
139	
140	const CURSE_SURCHARGE_RATE = 0.5;
141	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
142	const HIGH_ENCHANTMENT_THRESHOLD = 5;
143	
144	const itemSurcharges = (item: Item): number => {
145	  const base = itemBasePremium(item);
146	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
147	  const highEnch =
148	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
149	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
150	      : 0;
151	  return curse + highEnch;
152	};
153	
154	const LOYALTY_DISCOUNT_RATE = 0.2;
155	const LOYALTY_YEARS_THRESHOLD = 2;
156	const FOLLOWUP_DISCOUNT_RATE = 0.15;
157	
158	const perItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
159	
160	const policyWideDiscounts = (
161	  basePremium: number,
162	  customer: Customer,
163	  isFollowUp: boolean,
164	): number => {
165	  const loyalty =
166	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
167	  const followUp = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
168	  return loyalty + followUp;
169	};
170	
171	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
172	  const basePremium = policyBasePremium(items);
173	  const surcharges = perItemSurcharges(items);
174	  const discounts = policyWideDiscounts(basePremium, customer, isFollowUp);
175	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
176	  const premiumBeforeFee = Math.ceil(basePremium + surcharges - discounts + firstInsurance);
177	  return premiumBeforeFee + PROCESSING_FEE;
178	};
179	
180	type PolicyState = { items: Item[]; remainingCap: number };
181	
182	const newPolicyState = (items: Item[]): PolicyState => ({
183	  items,
184	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
185	});
186	
187	export const runScenario = (scenario: Scenario): unknown => {
188	  const policies: PolicyState[] = [];
189	  const results = scenario.steps.map((step) => {
190	    if (step.op === "quote") {
191	      validateItemTypes(step.items);
192	      const isFollowUp = policies.length > 0;
193	      policies.push(newPolicyState(step.items));
194	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
195	    }
196	    const policy = policies[step.policy];
197	    const result = processClaim(policy.items, step.incident, policy.remainingCap);
198	    policy.remainingCap = result.remainingCap;
199	    return result;
200	  });
201	  return { results };
202	};
