1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const insuranceValueForType = (type: string): number => INSURANCE_VALUE_BY_TYPE[type] ?? 0;
32	
33	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM_BY_TYPE));
34	
35	const validateItemTypes = (items: Item[]): void => {
36	  for (const item of items) {
37	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
38	      throw new Error(`Unknown item type: ${item.type}`);
39	    }
40	  }
41	};
42	
43	const DEDUCTIBLE = 100;
44	const CAP_MULTIPLIER = 2;
45	
46	const policyInsuranceSum = (items: Item[]): number =>
47	  sum(items.map((item) => insuranceValueForType(item.type)));
48	
49	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
50	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
51	
52	const reimbursableAmount = (damage: Damage, item: Item | undefined): number => {
53	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
54	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
55	  }
56	  return damage.amount;
57	};
58	
59	const damagePayout = (damage: Damage, item: Item | undefined): number =>
60	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
61	
62	const countBy = <T>(xs: T[], keyOf: (x: T) => string): Map<string, number> => {
63	  const counts = new Map<string, number>();
64	  for (const x of xs) {
65	    const k = keyOf(x);
66	    counts.set(k, (counts.get(k) ?? 0) + 1);
67	  }
68	  return counts;
69	};
70	
71	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
72	  const itemCounts = countBy(items, (item) => item.type);
73	  const damageCounts = countBy(damages, (damage) => damage.itemType);
74	  for (const [type, damageCount] of damageCounts) {
75	    const insuredCount = itemCounts.get(type) ?? 0;
76	    if (damageCount > insuredCount) {
77	      throw new Error(`Claim has ${damageCount} damages of type ${type} but policy covers only ${insuredCount}`);
78	    }
79	  }
80	};
81	
82	const validateDamageAmounts = (damages: Damage[]): void => {
83	  for (const damage of damages) {
84	    if (damage.amount < 0) {
85	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
86	    }
87	  }
88	};
89	
90	const processClaim = (
91	  items: Item[],
92	  incident: Incident,
93	  remainingCap: number,
94	): { payout: number; remainingCap: number } => {
95	  validateDamageAmounts(incident.damages);
96	  validateDamageCounts(items, incident.damages);
97	  const rawPayout = sum(
98	    incident.damages.map((damage) =>
99	      damagePayout(damage, items.find((item) => item.type === damage.itemType)),
100	    ),
101	  );
102	  const payout = Math.floor(Math.min(rawPayout, remainingCap));
103	  return { payout, remainingCap: remainingCap - payout };
104	};
105	
106	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
107	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
108	
109	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
110	const BLOCK_SIZE = 3;
111	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
112	
113	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
114	
115	const componentGroupPremium = (type: string, count: number): number =>
116	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
117	
118	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
119	
120	const policyBasePremium = (items: Item[]): number => {
121	  const mainItems = items.filter((item) => !isComponent(item));
122	  const componentItems = items.filter(isComponent);
123	  const componentCounts = countBy(componentItems, (item) => item.type);
124	
125	  const mainTotal = sum(mainItems.map(itemBasePremium));
126	  const componentTotal = sum(
127	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
128	  );
129	
130	  return mainTotal + componentTotal;
131	};
132	
133	const CURSE_SURCHARGE_RATE = 0.5;
134	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
135	const HIGH_ENCHANTMENT_THRESHOLD = 5;
136	
137	const itemSurcharges = (item: Item): number => {
138	  const base = itemBasePremium(item);
139	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
140	  const highEnch =
141	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
142	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
143	      : 0;
144	  return curse + highEnch;
145	};
146	
147	const LOYALTY_DISCOUNT_RATE = 0.2;
148	const LOYALTY_YEARS_THRESHOLD = 2;
149	const FOLLOWUP_DISCOUNT_RATE = 0.15;
150	
151	const perItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
152	
153	const policyWideDiscounts = (
154	  basePremium: number,
155	  customer: Customer,
156	  isFollowUp: boolean,
157	): number => {
158	  const loyalty =
159	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
160	  const followUp = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
161	  return loyalty + followUp;
162	};
163	
164	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
165	  const basePremium = policyBasePremium(items);
166	  const surcharges = perItemSurcharges(items);
167	  const discounts = policyWideDiscounts(basePremium, customer, isFollowUp);
168	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
169	  const premiumBeforeFee = Math.ceil(basePremium + surcharges - discounts + firstInsurance);
170	  return premiumBeforeFee + PROCESSING_FEE;
171	};
172	
173	type PolicyState = { items: Item[]; remainingCap: number };
174	
175	const newPolicyState = (items: Item[]): PolicyState => ({
176	  items,
177	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
178	});
179	
180	export const runScenario = (scenario: Scenario): unknown => {
181	  const policies: PolicyState[] = [];
182	  const results = scenario.steps.map((step) => {
183	    if (step.op === "quote") {
184	      validateItemTypes(step.items);
185	      const isFollowUp = policies.length > 0;
186	      policies.push(newPolicyState(step.items));
187	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
188	    }
189	    const policy = policies[step.policy];
190	    const result = processClaim(policy.items, step.incident, policy.remainingCap);
191	    policy.remainingCap = result.remainingCap;
192	    return result;
193	  });
194	  return { results };
195	};
